import{_ as e,o as a,c as r,ae as l}from"./chunks/framework.DrYEjkpc.js";const p=JSON.parse('{"title":"Claudeception","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-claudeception.md","filePath":"radar/tech-claudeception.md"}'),o={name:"radar/tech-claudeception.md"};function i(n,t,d,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="claudeception" tabindex="-1">Claudeception <a class="header-anchor" href="#claudeception" aria-label="Permalink to &quot;Claudeception&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 生成 / Skill 优化 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.69</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 在 Claude Code 每次会话中，通过 Hook 机制<strong>自动评估并提取</strong>&quot;值得记住&quot;的 Skill —— 让 Agent 不再每天失忆。</p><p><strong>来源</strong>:</p><ul><li>社区开源（<strong>2.3K+ ★</strong> · MIT）</li><li>作者：blader</li></ul><p><strong>链接</strong>:</p><ul><li>GitHub：<a href="https://github.com/blader/Claudeception" target="_blank" rel="noreferrer">blader/Claudeception</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="核心原理-四条件-skill-提取" tabindex="-1">核心原理：四条件 Skill 提取 <a class="header-anchor" href="#核心原理-四条件-skill-提取" aria-label="Permalink to &quot;核心原理：四条件 Skill 提取&quot;">​</a></h3><p>不是什么都记 —— 只提取满足以下<strong>四个条件</strong>的知识：</p><ol><li><strong>可复用</strong> — 不只对当前项目有用</li><li><strong>非平凡</strong> — 不是查文档就能知道的（间接过滤了模型已知知识）</li><li><strong>具体</strong> — 能描述精确的触发条件</li><li><strong>已验证</strong> — 实际生效过</li></ol><p>每个会话通常只提取 1-3 个 Skill。</p><h3 id="语义精准的-description" tabindex="-1">语义精准的 description <a class="header-anchor" href="#语义精准的-description" aria-label="Permalink to &quot;语义精准的 description&quot;">​</a></h3><p>不写&quot;帮助解决数据库问题&quot;，而写 <code>Fix for PrismaClientKnownRequestError in serverless environment with connection pool exhaustion</code>。下次遇到同样的错误信息时 Skill 能被精准召回。</p><h3 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h3><p>调试 Next.js <code>getServerSideProps</code> 在 Edge Runtime 下不可用 → Claudeception 提取：</p><ul><li>触发条件：使用 getServerSideProps + Edge Runtime</li><li>解法：改用 middleware 或 app router</li><li>验证状态：已在当前项目中验证</li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>仅面向 <strong>Claude Code 平台</strong></li><li>Skill 不跨用户共享（vs SkillClaw / OpenSpace 的集体学习模式）</li><li>提取质量依赖 LLM 自身判断，无外部验证</li><li>无公开的定量评测数据</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.70</td><td>已稳定可用，2.3K+ ★（MIT）</td></tr><tr><td>创新性</td><td>0.55</td><td>四条件 + Hook 机制是巧妙工程化</td></tr><tr><td>落地程度</td><td>0.75</td><td>Claude Code 用户广泛安装</td></tr><tr><td>生态活跃度</td><td>0.80</td><td>社区活跃，持续迭代</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.69</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://github.com/blader/Claudeception" target="_blank" rel="noreferrer">GitHub - Claudeception</a></li></ul>',31)])])}const g=e(o,[["render",i]]);export{p as __pageData,g as default};
